insert into public.produtos (sku, nome, descricao, categoria, preco, imagem_url, unidade, ativo)
values
  ('arom-1', 'Aromatizante Algodão 500ml', 'O Aromatizante Algodão é indicado para quem deseja perfumar ambientes com suavidade e sensação de limpeza. Ideal para salas, quartos, banheiros e outros espaços fechados, deixa um aroma leve e agradável no dia a dia.', 'Limpeza', 12.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-aromatizante-algodao-cd1fb1be66.png', 'un', true),
  ('arom-2', 'Aromatizante Amadeirado 500ml', 'O Aromatizante Amadeirado é ideal para quem prefere ambientes perfumados com uma fragrância mais marcante e sofisticada. Pode ser utilizado em diversos cômodos, trazendo sensação de conforto e elegância ao espaço.', 'Limpeza', 12.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-aromatizante-amadeirado-bda511459a.png', 'un', true),
  ('arom-3', 'Aromatizante Limão Siciliano 500ml', 'O Aromatizante Limão Siciliano é perfeito para quem busca frescor e leveza na perfumação dos ambientes. Seu aroma cítrico ajuda a deixar salas, cozinhas, banheiros e quartos mais agradáveis e com sensação de limpeza.', 'Limpeza', 12.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-aromatizante-limao-siciliano-0340664933.png', 'un', true),
  ('auto-1', 'Aromatizante Classic 60ml', 'O Aromatizante Classic é indicado para perfumar o interior do veículo com praticidade e boa fixação. Ideal para uso após a lavagem, ajuda a manter a sensação de carro limpo por mais tempo.', 'Limpeza', 9.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-aromatizante-classic-60ml-bbdb29b656.png', 'un', true),
  ('auto-2', 'Aromatizante Fresh 60ml', 'O Aromatizante Fresh é ideal para quem busca um perfume agradável e sensação prolongada de frescor no carro. Fácil de aplicar, é uma ótima opção para finalizar a higienização interna do veículo.', 'Limpeza', 9.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-aromatizante-fresh-60ml-60350434e4.png', 'un', true),
  ('auto-3', 'Detergente Automotivo com Cera 5L | 2L | 50L', 'O Detergente Automotivo com Cera é indicado para quem quer unir limpeza, brilho e praticidade em um só produto. Ideal para lavagens frequentes, ajuda na conservação da pintura e deixa o veículo com melhor acabamento.', 'Limpeza', 24.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-detergente-automotivo-com-cera-5l-2l-7f98948eb3.png', 'un', true),
  ('auto-4', 'Gel para Painel 3,5L | 500g', 'O Gel para Painel é ideal para renovar e proteger as partes plásticas internas do veículo. Além de realçar o brilho, ajuda a evitar o ressecamento e ainda deixa um perfume agradável no interior do carro. Disponível em 3,5L (uso profissional) e 500g (uso doméstico).', 'Limpeza', 14.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-gel-para-painel-3-5l-26de94679b.png', 'un', true),
  ('auto-6', 'Limpa Alumínio 5L | 50L', 'O Limpa Alumínio foi desenvolvido para a limpeza de alumínio e partes metálicas, sendo uma opção prática para remover sujeiras e marcas do uso diário. É um produto indicado para quem busca mais eficiência na higienização automotiva e de superfícies específicas.', 'Limpeza', 25.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpa-aluminio-5l.webp', 'un', true),
  ('auto-7', 'Pasta Mecânica 500g', 'A Pasta Mecânica é indicada para a remoção de graxa, óleo e resíduos pesados das mãos, sendo ideal para uso em oficinas, indústrias e trabalhos mecânicos. Sua fórmula promove limpeza eficiente sem necessidade de solventes agressivos.', 'Limpeza', 12.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-pasta-mecanica-500g-662bdcd039.png', 'un', true),
  ('auto-8', 'Preteador para Painel e Pneu 500ml | 5L', 'O Preteador de Painel e Pneu é ideal para restaurar o visual de pneus, painéis e partes plásticas com mais praticidade. Além de proteger, ajuda a valorizar o acabamento e ainda deixa um aroma suave no interior do veículo. Disponível em 500ml (uso doméstico) e 5L (uso profissional, alto rendimento).', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-preteador-painel-pneu-500ml.webp', 'un', true),
  ('auto-10', 'Preteador de Pneu com Silicone 500ml | 5L', 'O Preteador de Pneu com Silicone foi desenvolvido para devolver brilho e aparência renovada à borracha, ajudando também na proteção contra ressecamento. Ideal para finalizar a limpeza do veículo. Disponível em 500ml (uso doméstico) e 5L (alto rendimento).', 'Limpeza', 14.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-preteador-de-pneu-500ml-544853bdb3.png', 'un', true),
  ('auto-12', 'Solumax (Desengraxante) 5L | 50L', 'O Solumax é um desengraxante concentrado indicado para remover graxa, óleo, fuligem e sujeiras pesadas com mais rapidez. Ideal para oficinas, motores, pisos e áreas de produção, oferece alto desempenho na limpeza intensa.', 'Limpeza', 28.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-solumax-desengraxante-5l-f2e16124ee.png', 'un', true),
  ('casa-1', 'Água para Lençol Bambu', 'A Água para Lençol Bambu é indicada para perfumar tecidos e ambientes com um aroma leve, refrescante e acolhedor. Ideal para roupas de cama, cortinas e estofados, ajuda a prolongar a sensação de conforto no dia a dia.', 'Limpeza', 14.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-agua-para-lencol-bambu-2778f28f9c.png', 'un', true),
  ('casa-2', 'Água para Lençol Flor de Cerejeira', 'A Água para Lençol Flor de Cerejeira é perfeita para quem busca um perfume suave e agradável em tecidos e ambientes. Ideal para trazer sensação de cuidado, bem-estar e aconchego aos espaços da casa.', 'Limpeza', 14.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-agua-para-lencol-flor-de-cerejeira-e24473bcaa.png', 'un', true),
  ('casa-3', 'Álcool Perfumado Flores 5L', 'O Álcool Perfumado Flores é indicado para quem busca praticidade e frescor na limpeza do dia a dia. Com rápida evaporação e fragrância floral marcante, pode ser utilizado em múltiplas superfícies, deixando o ambiente limpo e suavemente perfumado.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-alcool-perfumado-flores-5l-37989de849.png', 'un', true),
  ('casa-4', 'Álcool Perfumado Lavanda 5L', 'O Álcool Perfumado Lavanda é ideal para quem quer unir limpeza prática e perfume agradável em um só produto. Sua aplicação ajuda a higienizar superfícies com rapidez, deixando um aroma de lavanda que transmite sensação de cuidado e bem-estar.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-alcool-perfumado-lavanda-5l-c683ce5309.png', 'un', true),
  ('casa-5', 'Álcool Perfumado Rosas 5L', 'O Álcool Perfumado Rosas é indicado para superfícies que pedem secagem rápida e um toque perfumado no acabamento. Ideal para vidros, bancadas e móveis, combina praticidade com uma fragrância agradável no ambiente.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-alcool-perfumado-rosas-5l-1eda534179.png', 'un', true),
  ('casa-6', 'Bicarbonato com Álcool 5L | 1L | 50L', 'O Bicarbonato com Álcool é uma opção prática para quem busca limpeza eficiente e ação desengordurante no dia a dia. Com aroma cítrico, pode ser utilizado em diversas superfícies da casa, trazendo sensação de limpeza e frescor.', 'Limpeza', 22.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-bicarbonato-com-alcool-5l-1l-c48e056bf7.png', 'un', true),
  ('casa-7', 'Desengordurante Quimi 90 5L | 1L', 'O Desengordurante Quimi 90 é indicado para remover gordura pesada com rapidez e eficiência. Ideal para chapas, coifas, cozinhas e superfícies laváveis, facilita a limpeza de áreas que exigem mais força na remoção da sujeira.', 'Limpeza', 25.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-desengordurante-quimi-90-5l-1l-724f3dae2f.png', 'un', true),
  ('casa-8', 'Desinfetante Citronela 5L | 2L | 50L', 'O Desinfetante Citronela é ideal para a limpeza diária de ambientes como banheiros, pisos, ralos e vasos sanitários. Além de higienizar, deixa um perfume característico que ajuda a manter o ambiente mais agradável.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-desinfetante-citronela-5l-2l-b4bd15aa3f.png', 'un', true),
  ('casa-9', 'Desinfetante Citrus 5L | 2L | 50L', 'O Desinfetante Citrus é indicado para quem prefere uma limpeza de rotina com sensação de frescor. Pode ser utilizado em diferentes ambientes da casa, contribuindo para a higienização e deixando um aroma cítrico agradável.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-desinfetante-citrus-5l-2l-8b5d51af5f.png', 'un', true),
  ('casa-10', 'Desinfetante Eucalipto 5L | 2L | 50L', 'O Desinfetante Eucalipto é uma ótima opção para higienizar superfícies e ambientes com praticidade. Seu aroma marcante deixa sensação de limpeza intensa, sendo ideal para uso diário em banheiros, pisos e áreas laváveis.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-desinfetante-eucalipto-5l-2l-f496ab839f.png', 'un', true),
  ('casa-11', 'Desinfetante Lavanda 5L | 2L | 50L', 'O Desinfetante Lavanda é indicado para quem busca limpeza eficiente com um perfume mais suave e agradável. Ideal para a rotina da casa, ajuda a manter os ambientes higienizados e perfumados por mais tempo.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-desinfetante-lavanda-5l-2l-42a6ba0c82.png', 'un', true),
  ('casa-12', 'Desinfetante Pinho 5L | 2L | 50L', 'O Desinfetante Pinho é ideal para quem procura uma fragrância mais clássica na limpeza do dia a dia. Pode ser usado em diferentes superfícies laváveis, contribuindo para a higienização e a sensação de ambiente bem cuidado.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-desinfetante-pinho-5l-2l-1805dc00c1.png', 'un', true),
  ('casa-13', 'Detergente Limão 5L | 2L | 50L', 'O Detergente Limão é indicado para a limpeza prática do dia a dia, ajudando na remoção de gorduras e sujeiras comuns com bom rendimento. Seu aroma cítrico deixa a rotina mais leve e agradável.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-detergente-limao-5l-2l-01877af951.png', 'un', true),
  ('casa-14', 'Detergente Neutro 5L | 2L | 50L', 'O Detergente Neutro é ideal para quem busca versatilidade e eficiência na limpeza diária. Pode ser utilizado em diferentes superfícies e utensílios, oferecendo praticidade com uma fórmula de uso corriqueiro.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-detergente-neutro-5l-2l-5a58f4db89.png', 'un', true),
  ('casa-15', 'Limpa Porcelanato 5L | 2L', 'O Limpa Porcelanato Quimiprol é indicado para quem deseja limpar e perfumar o porcelanato sem agredir o material. Sua proposta é unir rendimento, praticidade e cuidado com esse tipo de superfície.', 'Limpeza', 21.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-limpa-porcelanato-5l-2l-ac6311173a.png', 'un', true),
  ('casa-16', 'Limpa Vidro 5L | 1L', 'O Limpa Vidro é ideal para quem quer vidros, espelhos e superfícies brilhantes com aparência de limpeza e melhor transparência. É uma opção prática para o dia a dia e para acabamentos mais caprichados.', 'Limpeza', 18.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-limpa-vidro-1l-9efddc00b4.png', 'un', true),
  ('casa-17', 'Limpador Perfumado Bamboo 5L', 'O Limpador Perfumado Bamboo é indicado para perfumar e limpar ambientes de forma prática, deixando a casa com sensação de frescor e cuidado. Ideal para quem gosta de fragrâncias suaves e elegantes.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpador-perfumado-bamboo-5l.webp', 'un', true),
  ('casa-18', 'Limpador Perfumado Cravo e Canela 5L', 'O Limpador Perfumado Cravo e Canela é perfeito para quem quer unir limpeza e uma fragrância mais envolvente no ambiente. Ideal para deixar a casa perfumada com um toque aconchegante e marcante.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpador-perfumado-cravo-canela-5l.webp', 'un', true),
  ('casa-19', 'Limpador Perfumado Floral 5L', 'O Limpador Perfumado Floral é indicado para a limpeza de rotina com um perfume delicado e agradável. Ajuda a manter a casa limpa, organizada e com sensação de frescor por mais tempo.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpador-perfumado-floral-5l.webp', 'un', true),
  ('casa-20', 'Limpador Perfumado Frutas Vermelhas 5L', 'O Limpador Perfumado Frutas Vermelhas é ideal para quem procura uma limpeza prática acompanhada de uma fragrância doce e envolvente. Deixa o ambiente agradável e com sensação de cuidado no acabamento.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpador-perfumado-frutas-vermelha-5l.webp', 'un', true),
  ('casa-21', 'Limpador Perfumado Kaiak 5L', 'O Limpador Perfumado Kaiak é indicado para quem gosta de ambientes com perfume mais fresco e moderno. Une limpeza diária com uma fragrância agradável, ideal para diferentes espaços da casa.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpador-perfumado-kaiak-5l.webp', 'un', true),
  ('casa-22', 'Limpador Perfumado Marine 5L', 'O Limpador Perfumado Marine é uma ótima escolha para quem prefere fragrâncias leves e refrescantes na limpeza da casa. Deixa o ambiente com sensação de limpeza e frescor logo após o uso.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpador-perfumado-marine-5l.webp', 'un', true),
  ('casa-23', 'Limpador Perfumado Talco 5L', 'O Limpador Perfumado Talco é indicado para quem busca uma fragrância suave, confortável e duradoura no ambiente. Ideal para a limpeza do dia a dia, deixando a casa com sensação acolhedora.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpador-perfumado-talco-5l.webp', 'un', true),
  ('casa-24', 'Quimiox Oxigênio Ativo 5L | 1L | 50L', 'O Quimiox Oxigênio Ativo é indicado para quem precisa de limpeza profunda e versatilidade em diferentes superfícies. Com oxigênio ativo e ação bactericida, é uma opção prática tanto para uso doméstico quanto profissional.', 'Limpeza', 21.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-multiuso-especial-quimiox-5l-1l-41389b79c9.png', 'un', true),
  ('casa-25', 'Multiuso Laranja 5L', 'O Multiuso Laranja é ideal para a limpeza prática do dia a dia em diferentes superfícies laváveis. Ajuda a remover sujeiras comuns e ainda deixa um aroma cítrico agradável no ambiente.', 'Limpeza', 21.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-multi-uso-laranja-5l.webp', 'un', true),
  ('casa-26', 'Multiuso Limão 5L', 'O Multiuso Limão é indicado para quem busca agilidade na limpeza e sensação de frescor no acabamento. Pode ser utilizado em vários pontos da casa, tornando a rotina mais simples e eficiente.', 'Limpeza', 21.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-multi-uso-limao-5l.webp', 'un', true),
  ('casa-27', 'Pasta Brilho 500g', 'A Pasta Brilho é ideal para quem deseja limpeza eficiente com brilho imediato em superfícies específicas. Sua proposta é facilitar a remoção da sujeira e valorizar o acabamento final.', 'Limpeza', 12.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-pasta-brilho-500g-f9c7e6f006.png', 'un', true),
  ('maos-1', 'Detergente para Mãos Dovar 5L | 2L', 'O Detergente para Mãos Dovar é indicado para a limpeza das mãos com bom rendimento e praticidade no uso diário. Sua fórmula balanceada é ideal para ambientes que exigem reposição frequente e eficiência na higienização.', 'Limpeza', 18.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-detergente-para-maos-dovar-5l-2l-89c6205d1b.png', 'un', true),
  ('maos-2', 'Detergente para Mãos Erva Doce 5L | 2L', 'O Detergente para Mãos Erva Doce é ideal para quem busca limpeza eficiente com uma fragrância agradável no uso diário. Sua proposta une rendimento, cuidado e sensação de bem-estar após a higienização.', 'Limpeza', 18.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-detergente-para-maos-erva-doce-5l-2l-f06ceb9d73.png', 'un', true),
  ('maos-3', 'Detergente para Mãos Vinólia 5L | 2L', 'O Detergente para Mãos Vinólia é indicado para a limpeza frequente das mãos com praticidade e bom desempenho. Sua fórmula balanceada proporciona rendimento e uma experiência mais agradável na rotina de uso.', 'Limpeza', 18.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-detergente-para-maos-vinolia-5l-2l-3fa72fbab9.png', 'un', true),
  ('lav-1', 'Água Sanitária 5L | 2L | 50L', 'A Água Sanitária Quimiprol é indicada para desinfecção de superfícies, higienização de ambientes e alvejamento de roupas brancas. É uma solução prática para quem busca limpeza profunda e versatilidade no uso diário.', 'Limpeza', 14.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-agua-sanitaria-5l-2l-3a0fa05a9b.png', 'un', true),
  ('lav-2', 'Água Sanitária Perfumada 5L | 50L', 'A Água Sanitária Perfumada é ideal para quem busca unir desinfecção eficiente com uma fragrância mais agradável no ambiente. Pode ser utilizada em roupas brancas e superfícies, trazendo praticidade à rotina de limpeza.', 'Limpeza', 16.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-agua-sanitaria-perfumada-5l-688e004c3e.jpg', 'un', true),
  ('lav-3', 'Alvejante sem Cloro 5L | 2L | 50L', 'O Alvejante sem Cloro é indicado para remover manchas difíceis sem agredir roupas coloridas e brancas. É uma opção segura para quem precisa potencializar a lavagem sem recorrer ao cloro tradicional.', 'Limpeza', 18.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-alvejante-sem-cloro-5l-2l-1316600f16.jpg', 'un', true),
  ('lav-4', 'Amaciante Azul 5L | 2L | 50L', 'O Amaciante Azul é ideal para proporcionar maciez, perfume clássico e bom rendimento na lavagem diária. Deixa as roupas mais agradáveis ao toque e com sensação de cuidado prolongado.', 'Limpeza', 17.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-amaciante-azul-5l-2l-b71174dbb8.jpg', 'un', true),
  ('lav-5', 'Amaciante Clean 5L | 2L | 50L', 'O Amaciante Clean é indicado para quem prefere um perfume mais leve e suave nas roupas. Sua proposta é entregar maciez e rendimento com uma fragrância discreta para o uso frequente.', 'Limpeza', 17.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-amaciante-clean-5l-2l-931cee9c98.jpg', 'un', true),
  ('lav-6', 'Amaciante Concentrado Carícia Bem Me Quer 1L', 'O Amaciante Concentrado Bem Me Quer Carícia é ideal para quem deseja roupas mais macias e perfumadas com menor quantidade por lavagem. Seu toque delicado faz dele uma ótima opção para o uso diário.', 'Limpeza', 13.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-amaciante-concentrado-caricia-1l-a09c9dd3c2.jpg', 'un', true),
  ('lav-7', 'Amaciante Concentrado Intenso Bem Me Quer 1L', 'O Amaciante Concentrado Bem Me Quer Intenso é indicado para quem gosta de perfume mais marcante e duradouro nas roupas. Além da maciez, oferece economia por lavagem e excelente rendimento.', 'Limpeza', 13.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-amaciante-concentrado-intenso-1l-fe283d0b1d.jpg', 'un', true),
  ('lav-8', 'Amaciante Concentrado Romance Bem Me Quer 1L', 'O Amaciante Concentrado Bem Me Quer Romance traz a maciez e o perfume floral envolvente que torna o cuidado com as roupas um momento especial. Sua fórmula concentrada rende muito mais por lavagem — você usa menos produto e mantém o aroma marcante por mais tempo nos tecidos. Ideal para quem ama roupas macias, perfumadas e bem cuidadas no dia a dia.', 'Limpeza', 13.90, '/bem-me-quer-romance.png', 'un', true),
  ('lav-9', 'Amaciante Encapsulado Premium 5L | 2L | 50L', 'O Amaciante Encapsulado Premium foi desenvolvido para quem deseja perfume duradouro que ativa com o toque. Além da maciez, oferece uma experiência diferenciada no cuidado com os tecidos.', 'Limpeza', 22.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-amaciante-encapsulado-premium-5l-2l-54157072f3.jpg', 'un', true),
  ('lav-10', 'Amaciante Rosa 5L | 2L | 50L', 'O Amaciante Rosa é indicado para quem prefere uma fragrância floral suave no cuidado com as roupas. Proporciona maciez, perfume agradável e bom rendimento no uso diário.', 'Limpeza', 17.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-amaciante-rosa-5l-2l-64f1650a76.jpg', 'un', true),
  ('lav-11', 'Amaciante Soft 5L | 2L | 50L', 'O Amaciante Soft é ideal para lavagens frequentes, oferecendo maciez, perfume suave e praticidade. É uma opção versátil para quem busca eficiência e sensação agradável nas roupas.', 'Limpeza', 17.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-amaciante-soft-5l-2l-3c5f8e59c4.jpg', 'un', true),
  ('lav-12', 'Lava Roupas Quimiplus 5L | 2L | 50L', 'O Lava Roupas Quimiplus é ideal para quem quer unir performance, praticidade e fragrância marcante na lavagem diária. Ajuda a remover manchas, valoriza as cores e é uma alternativa eficiente para roupas que não podem receber cloro.', 'Limpeza', 22.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-lava-roupas-quimiplus-5l-2l-333f63ad30.jpg', 'un', true),
  ('lav-13', 'Sabão Líquido Azul 5L | 2L | 50L', 'O Sabão Líquido Azul é indicado para limpeza profunda dos tecidos com perfume agradável e alto rendimento. É uma opção prática para substituir o sabão em pó, com menos resíduos e mais facilidade no uso.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-sabao-liquido-azul-5l-2l-b01e95eec1.jpg', 'un', true),
  ('lav-14', 'Sabão Líquido de Coco 5L | 2L | 50L', 'O Sabão Líquido de Coco é ideal para quem busca limpeza eficiente com perfume leve e sensação prolongada de cuidado. Sua formulação líquida facilita o uso e ajuda a preservar melhor os tecidos.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/02/cover-sabao-liquido-de-coco-5l-2l-5ee16eef40.jpg', 'un', true),
  ('lav-15', 'Sabão Líquido Herbal 5L | 2L | 50L', 'O Sabão Líquido Herbal é indicado para quem deseja limpeza intensa com toque suave e fragrância herbal agradável. É uma boa escolha para roupas do dia a dia e para quem valoriza sensação de frescor nas peças.', 'Limpeza', 19.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-sabao-liquido-herbal-5l-2l-d465f75454.png', 'un', true),
  ('lav-16', 'Tira Manchas em Pó 500g', 'O Tira Manchas em Pó é ideal para potencializar a lavagem e auxiliar na remoção de manchas difíceis. Pode ser usado como reforço na máquina ou de molho, sendo uma opção prática para quem busca melhor desempenho na lavanderia.', 'Limpeza', 12.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-tira-manchas-em-po-500g-23fe7560d2.jpg', 'un', true),
  ('lav-17', 'Percarbonato de Sódio 1Kg', 'O Percarbonato de Sódio é indicado para quem busca reforço na limpeza e mais eficiência na remoção de manchas no dia a dia. Com ação versátil, ele pode ser utilizado para potencializar a lavagem de roupas, auxiliar na limpeza de superfícies e contribuir para uma higienização mais profunda. Ideal para quem procura praticidade, rendimento e um aliado eficaz na rotina de limpeza.', 'Limpeza', 18.90, '/percarbonato.webp', 'un', true),
  ('lp-1', 'Cloro 5L | 2L | 50L', 'O Cloro é indicado para limpezas pesadas e desinfecção de ambientes que exigem ação mais intensa. Ideal para superfícies, pisos e áreas de uso frequente, entrega praticidade e potência na higienização.', 'Limpeza', 15.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-cloro-2l-37cf9cb8e7.png', 'un', true),
  ('lp-2', 'Detergente Clorado 5L | 2L | 50L', 'O Detergente Clorado une ação desengordurante e poder desinfetante em um só produto. É indicado para limpezas profundas em forros, paredes, pisos e até roupas brancas com sujeiras mais difíceis.', 'Limpeza', 22.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/06/cover-detergente-clorado-5l-2l-14a84fcb8a.png', 'un', true),
  ('lp-3', 'Hipoclorito de Sódio 5L | 50L', 'O Hipoclorito de Sódio é ideal para quem precisa de desinfecção potente em diferentes aplicações. Indicado para superfícies, pisos e telhados, é uma solução de uso forte para rotinas de higienização intensa.', 'Limpeza', 18.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2026/01/cover-hipoclorito-de-sodio-5l-f1f410750d.png', 'un', true),
  ('lp-4', 'Limpa Piso 5L', 'O Limpa Piso é indicado para pisos encardidos e com sujeira impregnada, sendo uma opção eficiente para limpezas mais pesadas. Ideal para restaurar a aparência de áreas que exigem maior poder de ação.', 'Limpeza', 21.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/04/cover-limpa-piso-5l.webp', 'un', true),
  ('pet-1', 'Neutralizador de Odores 5L | 2L', 'O Neutralizador de Odores é indicado para eliminar cheiros desagradáveis causados por pets de forma prática e eficiente. Sua ação atua na origem do odor, ajudando a manter o ambiente mais limpo, agradável e confortável no dia a dia.', 'Limpeza', 22.90, 'https://www.quimiprol.com.br/doutor/uploads/6/produtos/2025/05/cover-neutralizador-de-odores-5l-414aa40154.jpg', 'un', true)
